/**
 * Returns a single combined SVG string with the Quran banner frame and the
 * surah name calligraphy for the given surah, ready for use with SvgXml.
 * Returns null if no calligraphy is available for this surah (show plain banner).
 */
export function buildBannerSvg(surahId: number, calligraphyColor: string): string | null {
  const c = CALLIGRAPHY[surahId];
  if (!c) return null;
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${BANNER_W} ${BANNER_H}" preserveAspectRatio="xMidYMid meet">
  ${BANNER_INNER}
  <g transform="translate(${BANNER_W / 2},${BANNER_H / 2}) scale(${c.s}) translate(-${c.cx},-${c.cy})" fill="${calligraphyColor}">
    ${c.p}
  </g>
</svg>`;
}

/**
 * Plain banner (no surah name) — used when no calligraphy exists for the surah.
 */
export const PLAIN_BANNER_SVG: string = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${BANNER_W} ${BANNER_H}" preserveAspectRatio="xMidYMid meet">
  ${BANNER_INNER}
</svg>`;
